import java.io.*;

public class Main {
    private static boolean isDouble(String s) {
        int n = s.length();
        int half = n / 2;
        return s.substring(0, half).equals(s.substring(half));
    }

    private static boolean canDeleteFromLeft(String s) {
        int n = s.length();
        int half = n / 2; // floor, because n is odd
        int i = 0, j = half + 1; // compare s[0..half] with s[half+1..]
        boolean skipped = false;
        while (i <= half && j < n) {
            if (s.charAt(i) == s.charAt(j)) {
                i++; j++;
            } else if (!skipped) {
                skipped = true; // delete s[i]
                i++;
            } else {
                return false;
            }
        }
        return true;
    }

    private static boolean canDeleteFromRight(String s) {
        int n = s.length();
        int half = n / 2; // floor, because n is odd
        int i = 0, j = half; // compare s[0..half-1] with s[half..]
        boolean skipped = false;
        while (i < half && j < n) {
            if (s.charAt(i) == s.charAt(j)) {
                i++; j++;
            } else if (!skipped) {
                skipped = true; // delete s[j]
                j++;
            } else {
                return false;
            }
        }
        return true;
    }

    private static boolean isSpecial(String s) {
        int n = s.length();
        if (n == 1) return false;
        if ((n & 1) == 0) {
            return isDouble(s);
        } else {
            return canDeleteFromLeft(s) || canDeleteFromRight(s);
        }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int D = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < D; t++) {
            String s = br.readLine().trim();
            out.append(isSpecial(s) ? "YES" : "NO").append('\n');
        }
        System.out.print(out.toString());
    }
}

